const titles = $input.first().json.titles || [];
const links = $input.first().json.links || [];
const dates = $input.first().json.dates || [];
const company = $('Get Competitors').item.json;

const articles = [];
const count = Math.min(titles.length, links.length);

for (let i = 0; i < count; i++) {
  let link = links[i];
  if (link && !link.startsWith('http')) {
    try {
      const base = new URL(company.news_page_url);
      link = link.startsWith('/') ? base.origin + link : base.origin + '/' + link;
    } catch(e) { continue; }
  }
  if (!link) continue;

  articles.push({
    json: {
      company_id: company.id,
      company_name: company.name,
      ticker: company.ticker,
      title: (titles[i] || '').trim(),
      source_url: link.trim(),
      published_date: (dates[i] || '').trim() || null,
      source_site: company.name
    }
  });
}

return articles.length > 0 ? articles : [{ json: { _empty: true, company_name: company.name } }];

const items = $input.all();
const newArticles = items.filter(item => item.json.id);

// Group by company
const byCompany = {};
for (const item of items) {
  const name = item.json.company_name || $('Normalize Articles').item?.json?.company_name || 'Unknown';
  if (!byCompany[name]) byCompany[name] = { total: 0, new: 0, titles: [] };
  byCompany[name].total++;
  if (item.json.id) {
    byCompany[name].new++;
    byCompany[name].titles.push(item.json.title);
  }
}

const companySummaries = Object.entries(byCompany).map(([name, data]) => 
  `${name}: ${data.titles.length > 0 ? data.titles.join('; ') : 'No new articles'}`
).join('\n');

return [{
  json: {
    new_count: newArticles.length,
    total_count: items.length,
    companies_count: Object.keys(byCompany).length,
    company_summaries: companySummaries
  }
}];

parameters.prompt:
Analyze the following competitor news from the graphite mining sector. For each company with news, provide a sentiment classification and brief analysis.

Competitor news:
{{$json.company_summaries}}

Respond in JSON format:
{
  "sentiments": [
    {
      "company_name": "...",
      "sentiment_label": "BREAKTHROUGH|FAILURE|STEADY",
      "sentiment_score": -1.0 to 1.0,
      "reasoning": "1-2 sentence explanation"
    }
  ],
  "fci_positioning": "2-3 paragraphs on what this means for FCI's competitive position",
  "company_analyses": "HTML formatted per-company analysis sections"
}

parameters.jsCode:
let gptResponse;
try {
  const content = $('GPT-5 Mini Analyze').first().json.message.content;
  // Strip markdown code fences if present
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  gptResponse = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse GPT response: ' + e.message, raw: $('GPT-5 Mini Analyze').first().json.message.content } }];
}

// Store sentiments
const sentimentInserts = (gptResponse.sentiments || []).map(s => ({
  json: {
    company_name: s.company_name,
    sentiment_label: s.sentiment_label,
    sentiment_score: s.sentiment_score,
    reasoning: s.reasoning
  }
}));

return [{
  json: {
    sentiments: gptResponse.sentiments || [],
    fci_positioning: gptResponse.fci_positioning || '',
    company_analyses: gptResponse.company_analyses || '',
    valid: true
  }
}];

const data = $input.first().json;
if (!data.valid) return [{ json: { skip: true } }];

const queries = data.sentiments.map(s => {
  const label = (s.sentiment_label || 'STEADY').replace(/'/g, "''");
  const reasoning = (s.reasoning || '').replace(/'/g, "''");
  const companyName = (s.company_name || '').replace(/'/g, "''");
  return `INSERT INTO sentiment_scores (company_id, sentiment_label, sentiment_score, reasoning)
    SELECT c.id, '${label}', ${s.sentiment_score || 0}, '${reasoning}'
    FROM companies c WHERE c.name = '${companyName}';`;
});

return [{ json: { query: queries.join('\n'), count: data.sentiments.length } }];

