const gptData = $('Validate GPT Response').first().json;
const mergeData = $('Merge Results').first().json;
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Build sentiment table rows
const sentimentColors = { 'BREAKTHROUGH': '#28a745', 'FAILURE': '#dc3545', 'STEADY': '#ffc107' };
const sentimentRows = (gptData.sentiments || []).map(s => {
  const color = sentimentColors[s.sentiment_label] || '#6c757d';
  return `<tr><td style="padding:8px;border-bottom:1px solid #eee;">${s.company_name}</td><td align="center" style="padding:8px;border-bottom:1px solid #eee;">${s.ticker || ''}</td><td align="center" style="padding:8px;border-bottom:1px solid #eee;"><span style="background-color:${color};color:#fff;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:bold;">${s.sentiment_label}</span></td><td align="center" style="padding:8px;border-bottom:1px solid #eee;">${s.sentiment_score}</td></tr>`;
}).join('');

let html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
